}
.elo-status-main {
  font-size: clamp(1rem, 1.8vw, 1.35rem);
  font-weight: 900;
  line-height: 1.1;
  margin-bottom: 0.85rem;
  overflow-wrap: anywhere;
}
.elo-change-list {
