}
.elo-message {
  background: #eff6ff;
  border: 1px solid #bfdbfe;
  border-left: 5px solid var(--elo-blue);
  border-radius: 8px;
  color: #1e3a8a;
  margin: 1rem 0 0;
  padding: 0.8rem 0.9rem;
}
.elo-trend {
  background: #f8fafc;
  border: 1px solid var(--elo-line);
  border-radius: 10px;
