  border: 1px solid #d8e0ea;
  border-radius: 10px;
  color: #172033;
  margin: 1rem 0 1.25rem;
  padding: 1rem;
}
.pfae-demo * {
  box-sizing: border-box;
}
.pfae-demo h4 {
  margin: 0 0 0.35rem;
}
.pfae-demo p {
  color: #475569;
  margin: 0;
}
.pfae-grid {
  display: grid;
  gap: 0.85rem;
  grid-template-columns: minmax(0, 0.95fr) minmax(0, 1.05fr);
  margin-top: 0.9rem;
}
.pfae-card {
  background: #ffffff;
  border: 1px solid #d8e0ea;
  border-radius: 8px;
  padding: 0.85rem;
}
.pfae-card h5 {
  color: #1e293b;
  font-size: 1rem;
  margin: 0 0 0.65rem;
}
.pfae-answer-grid {
  display: grid;
  gap: 0.5rem;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  margin-bottom: 0.85rem;
}
.pfae-answer {
  align-items: center;
  background: #f8fafc;
  border: 1px solid #d8e0ea;
  border-radius: 8px;
  color: #475569;
  cursor: pointer;
  display: flex;
  font-weight: 900;
  gap: 0.45rem;
  justify-content: center;
  padding: 0.55rem 0.65rem;
  transition: background 180ms ease, border-color 180ms ease, color 180ms ease;
}
.pfae-answer input {
  accent-color: #2563eb;
  margin: 0;
}
.pfae-answer.correct.active {
  background: #dcfce7;
  border-color: #86efac;
  color: #166534;
}
.pfae-answer.incorrect.active {
  background: #fee2e2;
  border-color: #fca5a5;
  color: #991b1b;
}
.pfae-answer.incorrect.active input {
  accent-color: #dc2626;
}
.pfae-slider-group {
  display: grid;
  gap: 0.7rem;
}
.pfae-slider-row {
  background: #f8fafc;
  border: 1px solid #d8e0ea;
  border-radius: 8px;
  display: grid;
  gap: 0.45rem;
  padding: 0.65rem;
}
.pfae-slider-row label {
  align-items: center;
  color: #1e293b;
  display: flex;
  font-weight: 850;
  gap: 0.75rem;
  justify-content: space-between;
}
.pfae-slider-row output {
  background: #eef2ff;
  border: 1px solid #c7d2fe;
  border-radius: 999px;
  color: #3730a3;
  font-weight: 900;
  min-width: 4rem;
  padding: 0.12rem 0.5rem;
  text-align: center;
}
.pfae-slider-row input[type="range"] {
  accent-color: #2563eb;
  width: 100%;
}
.pfae-probability-note {
  background: #eff6ff;
  border: 1px solid #bfdbfe;
  border-radius: 8px;
  color: #1e3a8a;
  font-size: 0.9rem;
  font-weight: 850;
  margin-top: 0.75rem;
  padding: 0.55rem 0.65rem;
}
.pfae-estimate-title {
  color: #334155;
  font-size: 0.95rem;
  font-weight: 900;
  margin-bottom: 0.55rem;
}
.pfae-flow {
  display: grid;
  gap: 0.4rem;
  margin-bottom: 0.7rem;
}
.pfae-value-box {
  background: #f8fafc;
  border: 1px solid #d8e0ea;
  border-radius: 8px;
  padding: 0.65rem;
}
.pfae-value-box span {
  color: #64748b;
  display: block;
  font-size: 0.8rem;
  font-weight: 850;
  margin-bottom: 0.18rem;
}
.pfae-value-box strong {
  color: #0f172a;
  font-size: 1.35rem;
  font-weight: 950;
  line-height: 1;
}
.pfae-arrow {
  color: #94a3b8;
  font-size: 1.15rem;
  font-weight: 950;
  line-height: 1;
  text-align: center;
}
.pfae-delta {
  background: #dbeafe;
  border-radius: 999px;
  color: #1d4ed8;
  display: inline-flex;
  font-size: 1.05rem;
  font-weight: 950;
  gap: 0.35rem;
  margin-bottom: 0.7rem;
  padding: 0.28rem 0.7rem;
}
.pfae-delta span {
  font-size: 0.82rem;
  font-weight: 850;
}
.pfae-bar {
  background: #e2e8f0;
  border-radius: 999px;
  height: 0.85rem;
  overflow: hidden;
}
.pfae-bar-fill {
  background: linear-gradient(90deg, #2563eb, #16a34a);
  border-radius: 999px;
  height: 100%;
  transition: width 180ms ease;
}
.pfae-feedback {
  background: #eff6ff;
  border: 1px solid #bfdbfe;
  border-left: 4px solid #2563eb;
  border-radius: 8px;
  color: #1e3a8a;
  font-weight: 800;
  line-height: 1.45;
  margin-top: 0.85rem;
  padding: 0.65rem 0.75rem;
}
@media (max-width: 820px) {
  .pfae-grid,
  .pfae-answer-grid {
    grid-template-columns: 1fr;
  }
}
&lt;/style&gt;
&lt;div class="pfae-demo"&gt;
  &lt;h4&gt;Wie verändert PFAE die Fähigkeitsschätzung?&lt;/h4&gt;
  &lt;p&gt;Lisa bearbeitet eine Aufgabe. Wählen Sie aus, ob ihre Antwort korrekt oder inkorrekt war, und verändern Sie die Lernraten für beide Fälle. Beobachten Sie, wie sich die Fähigkeitsschätzung von Lisa nach der Lerninteraktion verändert und vergleichen Sie die Auswirkungen beider Antwortmöglichkeiten.&lt;/p&gt;

  &lt;div class="pfae-grid"&gt;
    &lt;div class="pfae-card"&gt;
      &lt;h5&gt;Lisas Antwort auswählen&lt;/h5&gt;
      &lt;div class="pfae-answer-grid" aria-label="Antwort auswählen"&gt;
        &lt;label class="pfae-answer correct active"&gt;
          &lt;input class="pfae-answer-input" type="radio" name="pfae-answer" value="correct" checked&gt;
          &lt;span&gt;✓ korrekt&lt;/span&gt;
        &lt;/label&gt;
        &lt;label class="pfae-answer incorrect"&gt;
          &lt;input class="pfae-answer-input" type="radio" name="pfae-answer" value="incorrect"&gt;
          &lt;span&gt;✗ inkorrekt&lt;/span&gt;
        &lt;/label&gt;
      &lt;/div&gt;

      &lt;div class="pfae-slider-group"&gt;
        &lt;div class="pfae-slider-row"&gt;
          &lt;label&gt;
            &lt;span&gt;Lernrate γ bei korrekter Antwort&lt;/span&gt;
            &lt;output class="pfae-gamma-output"&gt;0,25&lt;/output&gt;
          &lt;/label&gt;
          &lt;input class="pfae-gamma-slider" type="range" min="0" max="0.5" step="0.01" value="0.25"&gt;
        &lt;/div&gt;
        &lt;div class="pfae-slider-row"&gt;
          &lt;label&gt;
            &lt;span&gt;Lernrate δ bei inkorrekter Antwort&lt;/span&gt;
            &lt;output class="pfae-delta-rate-output"&gt;0,10&lt;/output&gt;
          &lt;/label&gt;
          &lt;input class="pfae-delta-slider" type="range" min="0" max="0.5" step="0.01" value="0.10"&gt;
        &lt;/div&gt;
      &lt;/div&gt;
      &lt;div class="pfae-probability-note"&gt;Angenommene Erfolgswahrscheinlichkeit: P = 0,60&lt;/div&gt;
    &lt;/div&gt;

    &lt;div class="pfae-card"&gt;
      &lt;h5&gt;Aktualisierung beobachten&lt;/h5&gt;
      &lt;div class="pfae-estimate-title"&gt;Fähigkeitsschätzung von Lisa&lt;/div&gt;
      &lt;div class="pfae-flow"&gt;
        &lt;div class="pfae-value-box"&gt;&lt;span&gt;vorher&lt;/span&gt;&lt;strong&gt;0,50&lt;/strong&gt;&lt;/div&gt;
        &lt;div class="pfae-arrow"&gt;↓&lt;/div&gt;
        &lt;div class="pfae-value-box"&gt;&lt;span&gt;nachher&lt;/span&gt;&lt;strong class="pfae-after-output"&gt;0,60&lt;/strong&gt;&lt;/div&gt;
      &lt;/div&gt;
      &lt;div class="pfae-delta"&gt;&lt;span&gt;Änderungswert&lt;/span&gt;&lt;strong class="pfae-change-output"&gt;+0,10&lt;/strong&gt;&lt;/div&gt;
      &lt;div class="pfae-bar"&gt;&lt;div class="pfae-bar-fill"&gt;&lt;/div&gt;&lt;/div&gt;
      &lt;div class="pfae-feedback"&gt;Bei einer korrekten Antwort steigt die Fähigkeitsschätzung von Lisa entsprechend der Lernrate γ.&lt;/div&gt;
    &lt;/div&gt;
  &lt;/div&gt;
&lt;/div&gt;
`

const pfaeAnswerInputs = Array.from(pfaeDemoContainer.querySelectorAll(".pfae-answer-input"))
const pfaeAnswerLabels = Array.from(pfaeDemoContainer.querySelectorAll(".pfae-answer"))
const pfaeGammaSlider = pfaeDemoContainer.querySelector(".pfae-gamma-slider")
const pfaeDeltaSlider = pfaeDemoContainer.querySelector(".pfae-delta-slider")
const pfaeGammaOutput = pfaeDemoContainer.querySelector(".pfae-gamma-output")
const pfaeDeltaRateOutput = pfaeDemoContainer.querySelector(".pfae-delta-rate-output")
const pfaeAfterOutput = pfaeDemoContainer.querySelector(".pfae-after-output")
const pfaeChangeOutput = pfaeDemoContainer.querySelector(".pfae-change-output")
const pfaeBarFill = pfaeDemoContainer.querySelector(".pfae-bar-fill")
const pfaeMessage = pfaeDemoContainer.querySelector(".pfae-feedback")

const pfaeThetaBefore = 0.5
const pfaeExpectedSuccess = 0.6

const formatPfaeNumber = value =&gt;
  value.toFixed(2).replace(".", ",")

const updatePfaeDemo = () =&gt; {
  const selectedAnswer = pfaeAnswerInputs.find(input =&gt; input.checked)?.value ?? "correct"
  const gamma = Number(pfaeGammaSlider.value)
  const delta = Number(pfaeDeltaSlider.value)
  const change = selectedAnswer === "correct"
    ? gamma * (1 - pfaeExpectedSuccess)
    : delta * pfaeExpectedSuccess
  const thetaAfter = pfaeThetaBefore + change

  pfaeAnswerLabels.forEach(label =&gt; {
    const input = label.querySelector("input")
    label.classList.toggle("active", input.checked)
  })

  pfaeGammaOutput.value = formatPfaeNumber(gamma)
  pfaeDeltaRateOutput.value = formatPfaeNumber(delta)
  pfaeAfterOutput.textContent = formatPfaeNumber(thetaAfter)
  pfaeChangeOutput.textContent = `+${formatPfaeNumber(change)}`
  pfaeBarFill.style.width = `${Math.min(100, thetaAfter * 100)}%`
  pfaeMessage.textContent = selectedAnswer === "correct"
    ? "Bei einer korrekten Antwort steigt die Fähigkeitsschätzung von Lisa entsprechend der Lernrate γ."
    : "Auch eine inkorrekte Antwort kann in PFAE zu einem Anstieg von Lisas Fähigkeitsschätzung führen, wenn die Bearbeitung als Lerngelegenheit modelliert wird."
}

pfaeAnswerInputs.forEach(input =&gt; input.addEventListener("change", updatePfaeDemo))
pfaeGammaSlider.addEventListener("input", updatePfaeDemo)
pfaeDeltaSlider.addEventListener("input", updatePfaeDemo)
updatePfaeDemo()

return pfaeDemoContainer
}






Wie die Simulation zeigt, hängt die Aktualisierung der Fähigkeitsschätzung nicht allein davon ab, ob eine Antwort richtig oder falsch war. Entscheidend ist vielmehr, mit welcher Lernrate beide Fälle gewichtet werden. Um dieses Verhalten abzubilden, schlagen Papoušek et al. sowie Pelánek eine Erweiterung des Elo-Verfahrens vor, die als Performance Factor Analysis Extended Elo (PFAE) bezeichnet wird. Die Grundidee besteht darin, korrekte und inkorrekte Antworten unterschiedlich zu behandeln. Während das klassische Elo-Verfahren für beide Fälle denselben Aktualisierungsmechanismus verwendet, nutzt PFAE getrennte Lernraten für erfolgreiche und nicht erfolgreiche Bearbeitungen (Papoušek u. a. 2014; Pelánek 2015, 2016).
Die Aktualisierung erfolgt dabei nach den folgenden Regeln (Pelánek 2016):
\[
\theta_{si,\text{neu}}
=
\begin{cases}
\theta_{si,\text{alt}}+\gamma(1-P_i),
& \text{falls die Antwort korrekt war}\\[4pt]
\theta_{si,\text{alt}}+\delta P_i,
& \text{falls die Antwort inkorrekt war}
\end{cases}
\]
Dabei beschreiben \(\gamma\) und \(\delta\) unterschiedliche Lernraten für korrekte beziehungsweise inkorrekte Antworten. Die Parameter erlauben es, den erwarteten Wissenszuwachs abhängig vom Ergebnis einer Aufgabe unterschiedlich zu modellieren (Pelánek 2016).
Die Motivation hinter diesem Ansatz liegt in der Beobachtung, dass Lernende auch aus Fehlern lernen können. Eine inkorrekte Antwort muss daher nicht zwangsläufig zu einer Verringerung der geschätzten Fähigkeit führen. Stattdessen kann sie als Hinweis darauf interpretiert werden, dass während der Bearbeitung ein Lernprozess stattgefunden hat. Das Modell versucht somit nicht nur den aktuellen Wissensstand abzuschätzen, sondern berücksichtigt zusätzlich mögliche Wissenszuwächse durch die Interaktion mit Lernaufgaben (Pelánek 2016).
Während das ursprüngliche Elo-Verfahren primär der Leistungsbewertung dient, rückt bei PFAE zunehmend die Modellierung von Lernprozessen in den Mittelpunkt. Die Erweiterung verdeutlicht damit eine zentrale Entwicklung adaptiver Lernsysteme: den Übergang von der reinen Wissensschätzung hin zur expliziten Modellierung individueller Lernverläufe (Pelánek 2016).




